function countVowels(str) {
  const vowels = ['a', 'e', 'i', 'o', 'u'];
  const count = {};

  for (let i = 0; i < str.length; i++) {
    const char = str[i].toLowerCase();

    if (vowels.includes(char)) {
      if (count[char]) {
        count[char]++;
      } else {
        count[char] = 1;
      }
    }
