      word.match(/^[a-z]*$/g) &&
      /[aeiou]/i.test(word) &&
      /[b-df-hj-np-tv-z]{1}[aeiou]{1}[b-df-hj-np-tv-z]{1}/i.test(word)
    ) {
      // If shortestWord is empty or the current word is shorter than shortestWord, update shortestWord
      if (shortestWord === "" || word.length < shortestWord.length) {
