```javascript
function capitalizeSentences(paragraph) {
  let result = '';
  let capitalizeNext = true;

  for (let i = 0; i < paragraph.length; i++) {
    const char = paragraph[i];

    // Check if the character is a period or a question mark
    if (char === '.' || char === '?') {
      // Ignore sentences with numbers or special characters
      if (/[^\w\s]/.test(paragraph[i - 1])) {
        result += char;
      } else {
        capitalizeNext = true;
        result += char;
      }
    } else if (capitalizeNext && /[a-z]/.test(char)) {
      // Capitalize the first letter of the sentence
      result += char.toUpperCase();
      capitalizeNext = false;
    } else {
      result += char;
    }
  }

  return result;
}

