```javascript
// Fibonacci cache to store previously calculated Fibonacci numbers
const fibonacciCache = {};

function fibonacci(n) {
  // Error handling for invalid input
  if (typeof n !== 'number' || n < 0) {
    throw new Error('Invalid input. Please enter a non-negative number.');
  }

  // Return an empty array for n = 0
  if (n === 0) {
    return [];
  }

  // Return [0] for n = 1
  if (n === 1) {
    return [0];
  }

  // Return [0, 1] for n = 2
  if (n === 2) {
    return [0, 1];
  }

  // Check if Fibonacci numbers for n are already calculated and cached
  if (fibonacciCache[n]) {
    return fibonacciCache[n];
  }

  // Calculate Fibonacci numbers
  let fibonacciNumbers = [0, 1];

  for (let i = 2; i < n; i++) {
    let fib = fibonacciNumbers[i-1] + fibonacciNumbers[i-2];
    fibonacciNumbers.push(fib);
  }

