```javascript
// Function to remove duplicates from a string
function removeDuplicates(str) {
  let result = "";
  for (let i = 0; i < str.length; i++) {
    if (result.indexOf(str[i]) === -1) {
      result += str[i];
    }
  }
  return result;
}

// Function to check if two strings are anagrams
function areAnagrams(str1, str2) {
  // Remove duplicates and convert to lowercase
  str1 = removeDuplicates(str1.toLowerCase().replace(/[^a-z]/g, ""));
  str2 = removeDuplicates(str2.toLowerCase().replace(/[^a-z]/g, ""));

  // Check if the lengths are different
  if (str1.length !== str2.length) {
    return false;
  }

  // Create a frequency counter object
  const frequencyCounter = {};

  // Count the frequency of characters in the first string
  for (let char of str1) {
    frequencyCounter[char] = (frequencyCounter[char] || 0) + 1;
  }

  // Decrement the frequency counter for characters in the second string
  for (let char of str2) {
    if (!frequencyCounter[char]) {
      return false;
    }
    frequencyCounter[char]--;
  }

  // Check if all frequencies are zero
  for (let key in frequencyCounter) {
    if (frequencyCounter[key] !== 0) {
      return false;
    }
  }

  return true;
}

