```python
import math

def is_prime(n, i=2):
    if n <= 2:
        return n == 2
    if n % i == 0:
        return False
    if i * i > n:
        return True
    return is_prime(n, i + 1)

def generate_primes(n=100):
    if n < 2:
        return []
    primes = generate_primes(n - 1)
    if is_prime(n):
        primes.append(n)
    return primes

def sieve_of_eratosthenes(n):
    primes = [True] * (n + 1)
    primes[0] = primes[1] = False
    for i in range(2, int(math.sqrt(n)) + 1):
        if primes[i]:
            for j in range(i * i, n + 1, i):
                primes[j] = False
    return [i for i, prime in enumerate(primes) if prime]

primes = generate_primes()
print(primes[::-1])

sieve_primes = sieve_of_eratosthenes(100)
print(sieve_primes[::-1])
