function isPalindrome(str) {
  // Remove non-alphanumeric characters and convert to lowercase
  const normalizedStr = str.replace(/[^a-zA-Z0-9]/g, '').toLowerCase();

  // Recursive helper function to check if the substring is a palindrome
  function isSubstringPalindrome(subStr, left, right) {
    if (left >= right) {
      // Base case: all characters have been checked
      return true;
    }

    // Check if the characters at left and right positions are equal
    if (subStr.charCodeAt(left) !== subStr.charCodeAt(right)) {
      return false;
    }

    // Move the left and right pointers towards the center
    return isSubstringPalindrome(subStr, left + 1, right - 1);
  }

  // Call the recursive helper function
  return isSubstringPalindrome(normalizedStr, 0, normalizedStr.length - 1);
}

