    if (num < 2) {
      return false;
    }
    for (let i = 2; i < num; i++) {
      if (num % i === 0) {
        return false;
      }
    }
    return true;
  };

  const generatePrimeNumbers = () => {
    const primes = [];
    for (let i = minRange; i <= maxRange; i++) {
      if (isPrime(i)) {
        primes.push(i);
      }
    }
    setPrimeNumbers(primes);
  };

  const handleRangeChange = (e) => {
    const { name, value } = e.target;
    if (name === "minRange") {
      setMinRange(parseInt(value));
    } else if (name === "maxRange") {
      setMaxRange(parseInt(value));
    }
  };

