  // Convert the included angle from degrees to radians
  let angle_B = (included_angle * Math.PI) / 180;

  // Calculate the length of BC
  let BC = side_1 * Math.sin(angle_B);

  // Calculate the area of the isosceles triangle
  let area = (1/2) * side_1 * side_1 * Math.sin(angle_B);

  // Round the area to 2 decimal places
  area = area.toFixed(2);

  return area;
}

