Here's a JavaScript function that sorts an array of strings in alphabetical order based on their lengths:

```javascript
function sortStrings(arr) {
  // Sort the array using the merge sort algorithm
  mergeSort(arr, 0, arr.length - 1);
}

function mergeSort(arr, start, end) {
  if (start < end) {
    var mid = Math.floor((start + end) / 2);
    mergeSort(arr, start, mid);
    mergeSort(arr, mid + 1, end);
    merge(arr, start, mid, end);
  }
}

function merge(arr, start, mid, end) {
  var leftArr = arr.slice(start, mid + 1);
  var rightArr = arr.slice(mid + 1, end + 1);
  var i = 0, j = 0, k = start;

  while (i < leftArr.length && j < rightArr.length) {
    if (leftArr[i].length < rightArr[j].length) {
      arr[k] = leftArr[i];
      i++;
    } else if (leftArr[i].length > rightArr[j].length) {
      arr[k] = rightArr[j];
      j++;
    } else {
      if (leftArr[i] < rightArr[j]) {
        arr[k] = leftArr[i];
        i++;
      } else {
        arr[k] = rightArr[j];
        j++;
      }
    }
    k++;
  }

  while (i < leftArr.length) {
    arr[k] = leftArr[i];
    i++;
    k++;
  }

  while (j < rightArr.length) {
    arr[k] = rightArr[j];
    j++;
    k++;
  }
}
```

To use the `sortStrings` function, you can pass an array of strings as an argument, and it will sort the array in place:

```javascript
var arr = ['banana', 'apple', 'cat', 'dog', 'elephant', 'ant'];
sortStrings(arr);
console.log(arr); // ['cat', 'dog', 'ant', 'apple', 'banana', 'elephant']
```

