function isPrime(number) {
  if (number < 2) return false;

  for (let i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) return false;
  }

  return true;
}

function isPalindrome(number) {
  const numberString = number.toString();
  const reversedNumberString = numberString.split('').reverse().join('');
  return numberString === reversedNumberString;
}

function findPrimePalindromes(limit) {
  const primePalindromes = [];

  for (let i = 2; i <= limit; i++) {
    if (isPrime(i) && isPalindrome(i)) {
      primePalindromes.push(i);
    }
  }

  return primePalindromes;
}

// Using the Sieve of Eratosthenes to find prime numbers up to a given limit
function findPrimesSieve(limit) {
  const primes = [];
  const sieve = new Array(limit + 1).fill(true);

  for (let i = 2; i <= Math.sqrt(limit); i++) {
    if (sieve[i]) {
      for (let j = i * i; j <= limit; j += i) {
        sieve[j] = false;
      }
    }
  }

  for (let i = 2; i <= limit; i++) {
    if (sieve[i]) {
      primes.push(i);
    }
  }

  return primes;
}

