```javascript
function removePunctuationAndSort(sentence) {
  const words = sentence.split(/\W+/);
  const wordCount = {};

  for (let word of words) {
    if (word in wordCount) {
      wordCount[word]++;
    } else {
      wordCount[word] = 1;
    }
  }

  const sortedWords = Object.entries(wordCount).sort((a, b) => b[1] - a[1]);

