function reverseArray(arr) {
  if (arr.length === 0 || !Array.isArray(arr)) {
    return arr;
  }

  // Check if the array is already sorted
  let isSorted = true;
  for (let i = 0; i < arr.length - 1; i++) {
    if (arr[i] > arr[i + 1]) {
      isSorted = false;
      break;
    }
  }

  if (isSorted) {
    return arr;
  }

  // Remove duplicates
  let uniqueArr = [];
  for (let i = 0; i < arr.length; i++) {
    let num = Math.trunc(arr[i]);
    if (!uniqueArr.includes(num)) {
      uniqueArr.push(num);
    }
  }

  // Reverse the array in-place
  let start = 0;
  let end = uniqueArr.length - 1;
  while (start < end) {
    let temp = uniqueArr[start];
    uniqueArr[start] = uniqueArr[end];
    uniqueArr[end] = temp;
    start++;
    end--;
  }

  return uniqueArr;
}

// Test cases
console.log(reverseArray([1, 2, 3, 4, 5])); // Output: [5, 4, 3, 2, 1]
console.log(reverseArray([])); // Output: []
console.log(reverseArray([1.5, 2.3, 3.7, 4.9])); // Output: [4, 3, 2, 1]
console.log(reverseArray([-5, 10, -3, 0, 2])); // Output: [2, 0, -3, 10, -5]
console.log(reverseArray([1000000000, 999999999, 1000000001])); // Output: [1000000001, 999999999, 1000000000]
```

