function validatePassword(password) {
  // Rule 1: The password must be at least 16 characters long.
  if (password.length < 16) {
    return false;
  }

  // Rule 2: The password must contain at least two uppercase letters and two lowercase letters.
  if (
    !/(?=(.*[A-Z]){2,})(?=(.*[a-z]){2,})/.test(password)
