  if (/\s/.test(password)) {
    return false;
  }

  // Rule 5: The password must not contain any consecutive repeating characters.
  if (/(.)\1{1,}/.test(password)) {
    return false;
  }

  // Rule 6: The password must not be a common password.
  const commonPasswords = [
    'password123',
    'qwerty',
    '123456',
    // Add more common passwords here...
  ];

  if (commonPasswords.includes(password)) {
    return false;
  }

  // Rule 7: The password must contain at least three numbers.
