Here's a JavaScript function that takes a paragraph as a parameter and capitalizes the first letter of each sentence, while ignoring sentences that contain numbers or special characters. It follows a time complexity of O(n), where n is the number of characters in the paragraph:

```javascript
function capitalizeSentences(paragraph) {
  let result = '';
  let capitalizeNext = true;

  for (let i = 0; i < paragraph.length; i++) {
    const char = paragraph[i];

    // Check if the character is a period or a question mark
    if (char === '.' || char === '?') {
      // Ignore sentences with numbers or special characters
      if (/[^\w\s]/.test(paragraph[i - 1])) {
        result += char;
      } else {
        capitalizeNext = true;
        result += char;
      }
    } else if (capitalizeNext && /[a-z]/.test(char)) {
      // Capitalize the first letter of the sentence
      result += char.toUpperCase();
      capitalizeNext = false;
    } else {
      result += char;
    }
  }

  return result;
}

