      } else {
        break;
      }
    }

    return predecessor?.key;
  }

  updateValue(key, newValue) {
    const node = this._searchNode(this.root, key);
    if (node !== null) {
      node.value = newValue;
    }
  }

  _searchNode(node, key) {
    if (node === null || key === node.key) return node;

    if (key < node.key) {
      return this._searchNode(node.left, key);
    } else {
      return this._searchNode(node.right, key);
    }
  }

  *[Symbol.iterator]() {
    yield* this._inOrderTraversal(this.root);
  }

  *_inOrderTraversal(node) {
    if (node === null) return;

    yield* this._inOrderTraversal(node.left);
    yield node.key;
    yield* this._inOrderTraversal(node.right);
  }
}

