    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key) {
    const value = this.cache.get(key);
    if (value) {
      // Move the accessed item to the end of the Map to mark it as most recently used
      this.cache.delete(key);
      this.cache.set(key, value);
    }
    return value;
  }

