function reverseAndRemoveDuplicates(inputString) {
  // Remove special characters
  let cleanedString = inputString.replace(/[^\w\s]|_/g, "").replace(/\s+/g, " ");

  // Split the string into an array of words
  let wordsArray = cleanedString.split(" ");

  // Reverse each word
  let reversedArray = wordsArray.map(word => {
    return word.split("").reverse().join("");
  });

  // Remove duplicate words
  let uniqueArray = [...new Set(reversedArray)];

  // Sort the array in reverse alphabetical order
  let sortedArray = uniqueArray.sort().reverse();

  // Join the array back into a string
  let result = sortedArray.join(" ");

  return result;
}
```

