    <section id="section1">
        <h1>Heading 1</h1>
        <h1>Heading 1</h1>
        <h1>Heading 1</h1>
    </section>

    <script>
        // Add class attribute to h1 tags in section with id "section1"
        var section1 = document.getElementById("section1");
        var h1Tags = section1.querySelectorAll("h1");
        for (var i = 0; i < h1Tags.length; i++) {
            h1Tags[i].classList.add("section-h1");
        }

        // Create new section with an h2 tag and add a different class attribute
        var section2 = document.createElement("section");
        section2.id = "section2";
        var h2Tag = document.createElement("h2");
        h2Tag.textContent = "Heading 2";
        h2Tag.classList.add("section-h2");
        section2.appendChild(h2Tag);
        document.body.appendChild(section2);
    </script>
</body>
</html>
