Here is an example implementation of a custom Promise-like function in JavaScript:

```javascript
function customPromise(resolveCallback, rejectCallback) {
  let resolved = false;
  let rejected = false;
  let resolvedValue;
  let rejectedError;
  let thenCallbacks = [];
  let catchCallbacks = [];
  let finallyCallback;

  function resolve(value) {
    if (!resolved && !rejected) {
      resolved = true;
      resolvedValue = value;
      runThenCallbacks();
      runFinallyCallback();
    }
  }

  function reject(error) {
    if (!resolved && !rejected) {
      rejected = true;
      rejectedError = error;
      runCatchCallbacks();
      runFinallyCallback();
    }
  }

  function runThenCallbacks() {
    thenCallbacks.forEach(callback => {
      callback(resolvedValue);
    });
  }

  function runCatchCallbacks() {
    catchCallbacks.forEach(callback => {
      callback(rejectedError);
    });
  }

  function runFinallyCallback() {
    if (finallyCallback) {
      finallyCallback();
    }
  }

  function then(callback) {
    thenCallbacks.push(callback);
    if (resolved) {
      runThenCallbacks();
    }
    return { then, catch, finally: finallyMethod, delay };
  }

  function catchMethod(callback) {
    catchCallbacks.push(callback);
    if (rejected) {
      runCatchCallbacks();
    }
    return { then, catch: catchMethod, finally: finallyMethod, delay };
  }

  function finallyMethod(callback) {
    finallyCallback = callback;
    if (resolved || rejected) {
      runFinallyCallback();
    }
    return { then, catch: catchMethod, finally: finallyMethod, delay };
  }

  function delay(time) {
    return {
      then: function(callback) {
        setTimeout(() => {
          callback(resolvedValue);
        }, time);
        return { then, catch: catchMethod, finally: finallyMethod, delay };
      },
      catch: function(callback) {
        setTimeout(() => {
          callback(rejectedError);
        }, time);
        return { then, catch: catchMethod, finally: finallyMethod, delay };
      },
      finally: function(callback) {
        setTimeout(() => {
          callback();
        }, time);
        return { then, catch: catchMethod, finally: finallyMethod, delay };
      },
      delay: delay
    };
  }

  return { then, catch: catchMethod, finally: finallyMethod, delay };
}
```

