```javascript
function countFrequency(arr) {
  let frequency = {};

  for (let i = 0; i < arr.length; i++) {
    let string = arr[i];

    if (typeof string !== 'string' || string.length < 3 || !/^[a-zA-Z]+$/.test(string)) {
      continue;
    }

    if (frequency[string]) {
      frequency[string]++;
    } else {
      frequency[string] = 1;
    }
  }

  return frequency;
}
