// Function to limit the maximum length and count remaining characters
function limitMaxLength(inputElement, maxLength) {
  // Update the remaining characters count
  function updateCount() {
    const remaining = maxLength - inputElement.value.length;
    countElement.textContent = remaining;

    // Highlight the input field when maximum length is reached
    if (remaining < 0) {
      inputElement.classList.add("max-length-reached");
    } else {
      inputElement.classList.remove("max-length-reached");
    }
  }

