  const countElement = document.createElement("span");
  countElement.textContent = maxLength;
  inputElement.parentNode.appendChild(countElement);

  // Bind input event to update count
  inputElement.addEventListener("input", updateCount);

  // Call updateCount on page load
  updateCount();
}

